DbUtil = {}

DbUtil.GAME_DATA = 1
DbUtil.SHOP_DATA = 2
DbUtil.PAY_DATA = 3 --付费数据
DbUtil.GUIDE_DATA = 4
DbUtil.ADVERT_DATA = 5

DBManager:addMustLoadSubKey(DbUtil.GAME_DATA)
DBManager:addMustLoadSubKey(DbUtil.SHOP_DATA)
DBManager:addMustLoadSubKey(DbUtil.PAY_DATA)
DBManager:addMustLoadSubKey(DbUtil.GUIDE_DATA)
DBManager:addMustLoadSubKey(DbUtil.ADVERT_DATA)

function DbUtil:getPlayerData(player)
    local keys = {
        DbUtil.GAME_DATA,
        DbUtil.SHOP_DATA,
        DbUtil.PAY_DATA,
        DbUtil.GUIDE_DATA,
        DbUtil.ADVERT_DATA,
    }

    DBManager:getPlayerManyData(player.userId, keys, function(uid, result)
        for subKey, data in pairs(result) do
            DbUtil:initDataFromDB(uid, data, subKey)
        end
    end)
end

function DbUtil:initDataFromDB(uid, data, subKey)
    local player = PlayerManager:getPlayerByUserId(uid)
    if player then
        player:initDataFromDB(data, subKey)
    end
end

function DbUtil:onPlayerGetDataFinish(player, data, subKey)
    --if player then
    --    player:initDataFromDB(data, subKey)
    --end
end

function DbUtil:CanSavePlayerData(player, subKey)
    return DBManager:isLoadDataFinished(player.userId, subKey)
end

local function savePlayerGameData(player, immediate)
    if not DbUtil:CanSavePlayerData(player, DbUtil.GAME_DATA) then
        return
    end
    local data = player.property:getSavePropertyData()
    DBManager:savePlayerData(player.userId, DbUtil.GAME_DATA, data, immediate)
end

local function savePlayerShopData(player, immediate)
    if not DbUtil:CanSavePlayerData(player, DbUtil.SHOP_DATA) then
        return
    end
    local data = {}
    data.shopFitnessEquip = player.shopFitnessEquip
    data.shopGene = player.shopGene
    data.shopAdvanced = player.shopAdvanced
    data.shopSkill = player.shopSkill
    data.equipmentSkill = player.equipmentSkill
    data.tokenShopFitnessEquip = player.tokenShopFitnessEquip
    data.tokenShopGene = player.tokenShopGene
    data.tokenShopSkill = player.tokenShopSkill
    

    
    DBManager:savePlayerData(player.userId, DbUtil.SHOP_DATA, data, immediate)
end

local function savePlayerPayData(player, immediate)
    if not DbUtil:CanSavePlayerData(player, DbUtil.PAY_DATA) then
        return
    end
    local data = player.property:getSavePayData()
    --print("savePlayerPayData " .. inspect.inspect(data))
    DBManager:savePlayerData(player.userId, DbUtil.PAY_DATA, data, immediate)
end

local function savePlayerGuideData(player, immediate)
    if not DbUtil:CanSavePlayerData(player, DbUtil.PAY_DATA) then
        return
    end
    local data = {}
    data.running_guides = player.running_guides
    data.finish_ids = player.finish_ids
    data.newGuideProgress = player.newGuideProgress
    DBManager:savePlayerData(player.userId, DbUtil.GUIDE_DATA, data, immediate)
end

local function savePlayerAdvertData(player, immediate)
    if not DbUtil:CanSavePlayerData(player, DbUtil.ADVERT_DATA) then
        return
    end
    local data = {}
    data.advertInfo = player.advertInfo
    DBManager:savePlayerData(player.userId, DbUtil.ADVERT_DATA, data, immediate)
end

function DbUtil:savePlayerData(player, immediate)
    if player == nil then
        return
    end
    savePlayerGameData(player, immediate)
    savePlayerShopData(player, immediate)
    savePlayerPayData(player, immediate)
    savePlayerGuideData(player, immediate)
    savePlayerAdvertData(player, immediate)
end

return DbUtil